/* ============================================================
   STATE MACHINE + ENVIO DE MENSAJES
   Credencial instagramApi se usa en los nodos de accion.
   Para adjuntos (video/imagen/audio) se usa el token via $vars:
     IG_ACCESS_TOKEN -> Long-lived Page Access Token
     IG_PAGE_ID      -> ID numerico de la cuenta Instagram
     SALES_LINK      -> Link de venta
     VIDEO_GHOST_FACELESS, IMAGE_PACK_EXTREMO, AUDIO_VENTAS
     IMAGEN_ALUMNOS_1 .. IMAGEN_ALUMNOS_6
   ============================================================ */

const ACCESS_TOKEN = $vars.IG_ACCESS_TOKEN || '';
const PAGE_ID      = $vars.IG_PAGE_ID      || '';
const SALES_LINK   = $vars.SALES_LINK      || 'https://tu-link-de-venta.com';

const MEDIA = {
  VIDEO_GHOST_FACELESS: $vars.VIDEO_GHOST_FACELESS || '',
  IMAGE_PACK_EXTREMO:   $vars.IMAGE_PACK_EXTREMO   || '',
  AUDIO_VENTAS:         $vars.AUDIO_VENTAS         || '',
  IMAGEN_ALUMNOS_1:     $vars.IMAGEN_ALUMNOS_1     || '',
  IMAGEN_ALUMNOS_2:     $vars.IMAGEN_ALUMNOS_2     || '',
  IMAGEN_ALUMNOS_3:     $vars.IMAGEN_ALUMNOS_3     || '',
  IMAGEN_ALUMNOS_4:     $vars.IMAGEN_ALUMNOS_4     || '',
  IMAGEN_ALUMNOS_5:     $vars.IMAGEN_ALUMNOS_5     || '',
  IMAGEN_ALUMNOS_6:     $vars.IMAGEN_ALUMNOS_6     || '',
};

const delay = ms => new Promise(r => setTimeout(r, ms));

async function sendDM(userId, message) {
  const res = await fetch(`https://graph.facebook.com/v21.0/${PAGE_ID}/messages`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${ACCESS_TOKEN}` },
    body: JSON.stringify({ recipient: { id: userId }, message, messaging_type: 'RESPONSE' })
  });
  const data = await res.json();
  if (data.error) console.error('[sendDM]', JSON.stringify(data.error));
  return data;
}

async function sendAttachment(userId, type, url) {
  return sendDM(userId, { attachment: { type, payload: { url, is_reusable: true } } });
}

/* --- Parseo del trigger --- */
const item = $input.first().json;
const field = item.field || '';

let eventType = 'unknown';
let senderId  = null;
let senderName = 'amigo';
let messageText = '';
let commentId = null;

if (field === 'messages') {
  eventType   = 'dm';
  senderId    = item.sender?.id;
  messageText = item.message?.text || '';
  // Story reply / story mention via messaging
  const atts  = item.message?.attachments || [];
  if (atts.some(a => a.type === 'story_mention')) eventType = 'story_mention';
  if (atts.some(a => a.type === 'story_reply'))   eventType = 'story_reply';
} else if (field === 'comments') {
  eventType   = 'comment';
  senderId    = item.value?.from?.id;
  senderName  = item.value?.from?.username || item.value?.from?.name || 'amigo';
  commentId   = item.value?.id;
  messageText = item.value?.text || '';
} else if (field === 'mentions') {
  eventType   = 'story_mention';
  senderId    = item.sender?.id || item.value?.commenter_id;
  senderName  = item.value?.from?.username || 'amigo';
  messageText = item.value?.text || '';
}

if (!senderId) return [{ json: { status: 'no_sender_id', field } }];

/* --- State machine --- */
const sd = $getWorkflowStaticData('global');
if (!sd.users) sd.users = {};
if (!sd.users[senderId]) sd.users[senderId] = { state: 0, name: senderName };
const user = sd.users[senderId];
const text = (messageText || '').toLowerCase().trim();
if (senderName !== 'amigo') user.name = senderName;
const name = user.name || 'amigo';

const KW = ['nexus','informacion','información','obtener','informações','info'];
const hasKW = KW.some(k => text.includes(k));

let action = 'none';
if (['comment','story_mention','story_reply'].includes(eventType)) {
  action = 'send_step_0'; user.state = 1; user.commentId = commentId;
} else if (eventType === 'dm') {
  if      (user.state === 0 || hasKW)                                               { action = 'send_step_0'; user.state = 1; }
  else if (user.state === 1 && (text.includes('me gustar') || text.includes('💪'))) { action = 'send_step_1'; user.state = 2; }
  else if (user.state === 2 && (text.includes('me gustar') || text.includes('💪'))) { action = 'send_step_2'; user.state = 3; }
  else if (user.state === 3 && (text.includes('si elias') || text.includes('🤯')))  { action = 'send_step_3'; user.state = 4; }
  else if (user.state === 4 &&  text.includes('si elias'))                          { action = 'send_step_4'; user.state = 5; }
}
sd.users[senderId] = user;

if (action === 'none') return [{ json: { status: 'no_action', state: user.state } }];

/* ============================================================
   PASO 0 - Intro
   La respuesta al comentario la maneja el nodo 'Responder Comentario'
   Este nodo solo envia el DM inicial
   ============================================================ */
if (action === 'send_step_0') {
  await sendDM(senderId, {
    text: `¡Hola ${name}, gracias por tu interes en querer emprender! 🙌\n\nEstoy emocionado de compartir mas detalles contigo de como es que hoy en dia podes generar mas ingresos con tus redes sociales.\n\n¿Conoces ya sobre negocios digitales? Por favor elegi una respuesta de aqui abajo 👇`,
    quick_replies: [{ content_type: 'text', title: 'me gustaría Elias 💪', payload: 'STEP1_YES' }]
  });
}

/* ============================================================
   PASO 1 - Ghost Faceless + Video
   ============================================================ */
else if (action === 'send_step_1') {
  await sendDM(senderId, { text: `Genial! Te paso a comentar que es METODO GHOST FACELESS 👻\n\nEste metodo permite tener un producto digital YA CREADO Y LISTO PARA DEJARTE GANANCIAS desde la primera semana gracias a las clases virtuales para poner en practica los 5 pasos del negocio.\n\n¿Te imaginas hacer 2000 USD extra por mes solo subiendo contenido previamente creado? 🤯 Podés verlo en mi destacada VIP 👆` });
  await delay(1000);
  await sendAttachment(senderId, 'video', MEDIA.VIDEO_GHOST_FACELESS);
  await delay(1500);
  await sendDM(senderId, {
    text: `Aca podes ver como recibo pagos en automatico y es lo que quiero que aprendas hoy... ¿Te gustaria? 🚀`,
    quick_replies: [{ content_type: 'text', title: 'me gustaría Elias 💪', payload: 'STEP2_YES' }]
  });
}

/* ============================================================
   PASO 2 - Pack Extremo
   ============================================================ */
else if (action === 'send_step_2') {
  await sendDM(senderId, { text: `¿Estas listo para convertirte en un maestro del marketing? 🚀\n\nCon el Pack Extremo tenes todo para generar 2.000 USD al mes 🤩\n\n🗓️ Guias de 90 dias\n🚀 Planes de lanzamiento\n🧲 101 Llamados a la accion\n💥 101 Ganchos para Reels\n🎬 Pack de videos Faceless\n\nTodo esto por menos de 30 USD! 🤯` });
  await delay(1000);
  await sendAttachment(senderId, 'image', MEDIA.IMAGE_PACK_EXTREMO);
  await delay(1000);
  await sendDM(senderId, {
    text: `¿Te gustaria ver resultados de alumnos ya ganando con el Pack Emprender? 👀`,
    quick_replies: [{ content_type: 'text', title: 'si Elias!! 🤯', payload: 'STEP3_YES' }]
  });
}

/* ============================================================
   PASO 3 - Resultados de alumnos (6 imagenes)
   ============================================================ */
else if (action === 'send_step_3') {
  await sendDM(senderId, { text: 'TE DEJO ACA DEBAJO GANANCIAS DE ALUMNOS 👇👇' });
  await delay(500);
  for (const k of ['IMAGEN_ALUMNOS_1','IMAGEN_ALUMNOS_2','IMAGEN_ALUMNOS_3','IMAGEN_ALUMNOS_4','IMAGEN_ALUMNOS_5','IMAGEN_ALUMNOS_6']) {
    await sendAttachment(senderId, 'image', MEDIA[k]);
    await delay(800);
  }
  await sendDM(senderId, {
    text: 'TE GUSTARIA COMENZAR Y SER UNO DE ELLOS? TAMBIEN VAS A RECIBIR LA FORMULA DE MI BOT AUTOMATICO DE GANANCIAS 🤖💰',
    quick_replies: [{ content_type: 'text', title: 'SI ELIAS!!', payload: 'STEP4_YES' }]
  });
}

/* ============================================================
   PASO 4 - Audio + Link de venta
   ============================================================ */
else if (action === 'send_step_4') {
  await sendDM(senderId, { text: `${name.toUpperCase()}\nESCUCHA ATENTAMENTE ESTE AUDIO 🎧` });
  await delay(500);
  await sendAttachment(senderId, 'audio', MEDIA.AUDIO_VENTAS);
  await delay(2000);
  await sendDM(senderId, { text: `AHORA SI PASEMOS A LA MEJOR PARTE 🔥\n\nTe dejo el link a nuestra pagina CON EL DESCUENTO DEL 50% 👇\n\n${SALES_LINK}` });
}

return [{ json: { action, senderId, senderName: name, commentId: user.commentId || commentId, state: user.state, eventType } }];
